&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;इससे यह स्पष्ट होता है कि&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;बालकः वृक्षान् सिञ्चति&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;।&amp;#39;&lt;/span&gt;&amp;nbsp;इस वाक्य का वाच्यपरिवर्तन&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;&lt;/span&gt;बालकेन वृक्षाः सिञ्च्यन्ते।&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rsquo;&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;होगा।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शब्द -&lt;/span&gt;&amp;nbsp;स्वागतम्&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धिविच्छेद -&lt;/span&gt;&amp;nbsp;सु + आगतम्&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि -&lt;/span&gt;&amp;nbsp;यण्&amp;zwnj; सन्धि&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सूत्र -&lt;/span&gt;&amp;nbsp;&amp;#39;इको यणचि&amp;#39; सूत्र से &amp;lsquo;इक्&amp;rsquo; अर्थात&amp;nbsp;&lt;u&gt;&amp;lsquo;इ/ई&amp;rsquo;, &amp;lsquo;उ/ऊ&amp;rsquo;, &amp;lsquo;ऋ/ऋ&amp;rsquo; और &amp;lsquo;लृ&amp;rsquo;&lt;/u&gt;&amp;nbsp;के आगे अगर&amp;nbsp;&lt;u&gt;कोइ भी स्वर(विजातीय)&lt;/u&gt;&amp;nbsp;आता है तब वहा&amp;nbsp;&lt;u&gt;यण् अर्थात् य्, व्, र्, ल्&lt;/u&gt;&amp;nbsp;होते&amp;nbsp;हैं।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नियम &amp;ndash;&lt;/span&gt;&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;इ/ई + स्वर = य् + स्वर&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;उ/ऊ + स्वर = व् + स्वर&lt;/strong&gt;&lt;/u&gt;&lt;/li&gt;
	&lt;li&gt;ऋ/ॠ + स्वर = र् + स्वर&lt;/li&gt;
	&lt;li&gt;लृ + स्वर = ल् + स्वर&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;स्पष्टीकरण&amp;nbsp;-&lt;/span&gt;&amp;nbsp;&lt;u&gt;&amp;lsquo;सु + आगतम्&lt;/u&gt;&lt;u&gt;&amp;rsquo;&lt;/u&gt;&amp;nbsp;में प्रथम पद के अन्त में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;उ&amp;rsquo;&lt;/span&gt;&amp;nbsp;और दुसरे पद के प्रारम्भ में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;आ&amp;rsquo;&lt;/span&gt;&amp;nbsp;होने से यहाँ&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;यण् सन्धि&amp;#39;&lt;/span&gt;&lt;/u&gt;&amp;nbsp;होगी।&lt;/p&gt;

&lt;p&gt;अतः स्पष्टिकरण के अनुसार&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;lsquo;&lt;/span&gt;&lt;strong&gt;सु + आगतम्&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rsquo;&lt;/span&gt;&amp;nbsp;का&amp;nbsp;सन्धि होकर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;स्वागतम्&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&amp;nbsp;होता है और यहाँ&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;यण् सन्धि&amp;#39;&lt;/span&gt;&lt;/u&gt;&amp;nbsp;होता है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;विकल्पों का स्पष्टीकरण -&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color: rgb(255, 255, 255); width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 85px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 113px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सूत्र&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नियम&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 214px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 85px;&quot;&gt;
			&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गुण सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 113px;&quot;&gt;
			&lt;p&gt;आद् गुणः&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p&gt;अ/आ + इ/ई = ए&lt;/p&gt;

			&lt;p&gt;अ/आ + उ/ऊ = ओ&lt;/p&gt;

			&lt;p&gt;अ/आ + ऋ/ॠ = अर्&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 214px;&quot;&gt;
			&lt;p&gt;उप + इन्द्र = उपेन्द्र&lt;/p&gt;

			&lt;p&gt;यथा + उचितम् = यथोचितम्&lt;/p&gt;

			&lt;p&gt;देव + ऋषि = देवर्षि&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 85px;&quot;&gt;
			&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;दीर्घ सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 113px;&quot;&gt;
			&lt;p&gt;अकः सवर्णे दीर्घः&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p&gt;अ/आ + अ/आ = आ&lt;/p&gt;

			&lt;p&gt;इ/ई + इ/ई = ई&lt;/p&gt;

			&lt;p&gt;उ/ऊ + उ/ऊ = ऊ&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 214px;&quot;&gt;
			&lt;p&gt;हिम + आलय = हिमालय&lt;/p&gt;

			&lt;p&gt;गिरी + ईश = गिरीश&lt;/p&gt;

			&lt;p&gt;भानु + उदय = भानूदय&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 85px;&quot;&gt;
			&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वृद्धि सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 113px;&quot;&gt;
			&lt;p&gt;वृद्धिरेचि&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p&gt;अ/आ + ए/ऐ = &amp;#39;ऐ&lt;/p&gt;

			&lt;p&gt;अ/आ + ओ/औ = औ&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 214px;&quot;&gt;
			&lt;p&gt;मम + एक = ममैक&lt;/p&gt;

			&lt;p&gt;जल + ओघः = जलौघः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 85px;&quot;&gt;
			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;यण्&amp;nbsp;सन्धि&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 113px;&quot;&gt;
			&lt;p&gt;इको यणचि&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p&gt;इ/ई + विजातीय स्वर = य्&amp;nbsp;&lt;/p&gt;

			&lt;p&gt;उ/ऊ + विजातीय स्वर = व्&lt;br /&gt;
			ऋ/ॠ + विजातीय स्वर = र्&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 214px;&quot;&gt;
			&lt;p&gt;नदी + अत्र = नद्यत्र&lt;/p&gt;

			&lt;p&gt;मधु + इति = मध्विति&lt;/p&gt;

			&lt;p&gt;पितृ + इच्छा = पित्रिच्छा&lt;/p&gt;

			&lt;div&gt;&amp;nbsp;&lt;/div&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि:-&amp;nbsp;&lt;/span&gt;दो शब्दों के संयोग से होने वाले परिवर्तन को सन्धि कहते हैं। जैसे-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;विद्या + आलय = विद्यालय।&lt;/li&gt;
	&lt;li&gt;रमा + ईश = रमेश&lt;/li&gt;
	&lt;li&gt;न + एकः = नैकः&lt;/li&gt;
	&lt;li&gt;सम्यक् + ज्ञानम् = सम्यग्ज्ञानम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि के प्रकार:-&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color: rgb(255, 255, 255); width: 370px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 161px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 21px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;स्वरसन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 21px;&quot;&gt;
			&lt;p&gt;स्वर वर्ण&amp;nbsp; का संयोग स्वर वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 161px; height: 21px;&quot;&gt;
			&lt;p&gt;विद्या + आलय = विद्यालय&lt;/p&gt;

			&lt;p&gt;महा + औषधि =&amp;nbsp; महौषधि&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;व्यंजनसन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p&gt;व्यंजन वर्ण का संयोग व्यंजन या स्वर वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 161px; height: 20px;&quot;&gt;
			&lt;p&gt;उत् + लास = उल्लास&lt;/p&gt;

			&lt;p&gt;तत् + लय = तल्लयः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विसर्गसन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p&gt;विसर्ग का सन्योग स्वर या व्यंजन वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 161px; height: 20px;&quot;&gt;
			&lt;p&gt;दुः + आत्मा = दुरात्मा&lt;/p&gt;

			&lt;p&gt;मनः + रथः = मनोरथः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;लभ्&amp;nbsp;(प्राप्त करना) &lt;span style=&quot;&quot;&gt;धातु का&amp;nbsp;&lt;/span&gt;लोट् लकार के विविध पुरुषों और वचनों के रूप निम्नलिखित प्रकार से चलता है-&lt;/p&gt;

