			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;द्विवचन&lt;/span&gt;&lt;/p&gt;
