		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 92px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्रथमपुरुष&lt;/span&gt;&lt;/p&gt;
