			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;लभताम्&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;लभेताम्&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;लभन्ताम्&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 92px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मध्यमपुरुष&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;लभस्व&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;लभेथाम्&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 120px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;लभध्वम्&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 92px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उत्तमपुरुष&lt;/span&gt;&lt;/p&gt;
